import { useLocation, useNavigate } from "react-router-dom";
import "./styles/LibrarianDashboard.css";

function LibrarianDashboard() {
  const location = useLocation();
  const navigate = useNavigate();

  const genre = location.state?.genre || "Unknown";

  return (
    <div className="dashboard-page">
      <h1 className="dashboard-title">
        Librarian Panel – {genre}
      </h1>

      <div className="dashboard-center">
        <div className="dash-card" onClick={() => navigate("/librarian/books", { state: { genre } })}>
          📚 View {genre} Books
        </div>

        <div className="dash-card" onClick={() => navigate("/librarian/add-book", { state: { genre } })}>
          ➕ Add New Book
        </div>

        <div className="dash-card">
          ✏️ Update Book Status
        </div>

        <div className="dash-card">
          ❌ Remove Book
        </div>
      </div>
    </div>
  );
}

export default LibrarianDashboard;
